// export default Dashboard;

import React, { useState, useEffect } from 'react';

const Dashboard = () => {
    const [user, setUser] = useState(null);
    const [activeTab, setActiveTab] = useState('overview');
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        // Check if user is authenticated
        const checkAuth = () => {
            const token = localStorage.getItem('authToken');
            const userRole = localStorage.getItem('userRole');
            const userEmail = localStorage.getItem('userEmail');

            if (!token) {
                // In a real app, would redirect to login
                window.location.href = '/';
                return;
            }

            setUser({
                email: userEmail || 'demo@example.com',
                role: userRole || 'student',
                name: userEmail?.split('@')[0] || 'Demo User'
            });
            setIsLoading(false);
        };

        // Simulate auth check
        setTimeout(checkAuth, 1000);
    }, []);

    const handleLogout = () => {
        localStorage.removeItem('authToken');
        localStorage.removeItem('userRole');
        localStorage.removeItem('userEmail');
        window.location.href = '/';
    };

    if (isLoading) {
        return (
            <div style={styles.loadingContainer}>
                <div style={styles.spinner}></div>
                <p>Loading dashboard...</p>
            </div>
        );
    }

    const renderStudentDashboard = () => (
        <>
            <div style={styles.statsGrid}>
                <div style={styles.statCard}>
                    <div style={{...styles.statIcon, backgroundColor: '#3b82f6'}}>
                        <span className="material-icons">school</span>
                    </div>
                    <div style={styles.statContent}>
                        <h3>Enrolled Courses</h3>
                        <p style={styles.statNumber}>4</p>
                    </div>
                </div>
                <div style={styles.statCard}>
                    <div style={{...styles.statIcon, backgroundColor: '#10b981'}}>
                        <span className="material-icons">assignment</span>
                    </div>
                    <div style={styles.statContent}>
                        <h3>Assignments Due</h3>
                        <p style={styles.statNumber}>3</p>
                    </div>
                </div>
                <div style={styles.statCard}>
                    <div style={{...styles.statIcon, backgroundColor: '#f59e0b'}}>
                        <span className="material-icons">schedule</span>
                    </div>
                    <div style={styles.statContent}>
                        <h3>Study Hours</h3>
                        <p style={styles.statNumber}>24</p>
                    </div>
                </div>
                <div style={styles.statCard}>
                    <div style={{...styles.statIcon, backgroundColor: '#8b5cf6'}}>
                        <span className="material-icons">grade</span>
                    </div>
                    <div style={styles.statContent}>
                        <h3>Average Grade</h3>
                        <p style={styles.statNumber}>A-</p>
                    </div>
                </div>
            </div>

            <div style={styles.dashboardContent}>
                <div style={styles.section}>
                    <h3>Recent Courses</h3>
                    <div style={styles.courseList}>
                        {[
                            { name: 'Data Science Fundamentals', icon: '📊', progress: 75 },
                            { name: 'Web Development', icon: '💻', progress: 60 },
                            { name: 'Machine Learning', icon: '🤖', progress: 45 }
                        ].map((course, idx) => (
                            <div key={idx} style={styles.courseItem}>
                                <div style={styles.courseIcon}>{course.icon}</div>
                                <div style={styles.courseInfo}>
                                    <h4>{course.name}</h4>
                                    <div style={styles.progressBar}>
                                        <div style={{...styles.progressFill, width: `${course.progress}%`}}></div>
                                    </div>
                                    <p>Progress: {course.progress}%</p>
                                </div>
                                <button style={styles.continueBtn}>Continue</button>
                            </div>
                        ))}
                    </div>
                </div>

                <div style={styles.section}>
                    <h3>Upcoming Tasks</h3>
                    <div style={styles.taskList}>
                        {[
                            { date: '25', month: 'May', task: 'Data Analysis Project', due: 'Due in 2 days' },
                            { date: '28', month: 'May', task: 'JavaScript Quiz', due: 'Due in 5 days' }
                        ].map((task, idx) => (
                            <div key={idx} style={styles.taskItem}>
                                <div style={styles.taskDate}>
                                    <span style={styles.day}>{task.date}</span>
                                    <span style={styles.month}>{task.month}</span>
                                </div>
                                <div style={styles.taskInfo}>
                                    <h4>{task.task}</h4>
                                    <p>{task.due}</p>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </>
    );

    const renderTeacherDashboard = () => (
        <>
            <div style={styles.statsGrid}>
                <div style={styles.statCard}>
                    <div style={{...styles.statIcon, backgroundColor: '#059669'}}>
                        <span className="material-icons">class</span>
                    </div>
                    <div style={styles.statContent}>
                        <h3>Active Courses</h3>
                        <p style={styles.statNumber}>3</p>
                    </div>
                </div>
                <div style={styles.statCard}>
                    <div style={{...styles.statIcon, backgroundColor: '#dc2626'}}>
                        <span className="material-icons">people</span>
                    </div>
                    <div style={styles.statContent}>
                        <h3>Total Students</h3>
                        <p style={styles.statNumber}>156</p>
                    </div>
                </div>
                <div style={styles.statCard}>
                    <div style={{...styles.statIcon, backgroundColor: '#7c3aed'}}>
                        <span className="material-icons">grading</span>
                    </div>
                    <div style={styles.statContent}>
                        <h3>Pending Grading</h3>
                        <p style={styles.statNumber}>12</p>
                    </div>
                </div>
                <div style={styles.statCard}>
                    <div style={{...styles.statIcon, backgroundColor: '#2563eb'}}>
                        <span className="material-icons">event</span>
                    </div>
                    <div style={styles.statContent}>
                        <h3>Classes Today</h3>
                        <p style={styles.statNumber}>2</p>
                    </div>
                </div>
            </div>

            <div style={styles.dashboardContent}>
                <div style={styles.section}>
                    <h3>My Courses</h3>
                    <div style={styles.courseList}>
                        {[
                            { name: 'Data Science 101', students: 45, time: 'MWF 10:00 AM' },
                            { name: 'Advanced Analytics', students: 32, time: 'TTh 2:00 PM' },
                            { name: 'Business Intelligence', students: 58, time: 'Online' }
                        ].map((course, idx) => (
                            <div key={idx} style={styles.courseItem}>
                                <div style={styles.courseIcon}>📚</div>
                                <div style={styles.courseInfo}>
                                    <h4>{course.name}</h4>
                                    <p>{course.students} Students • {course.time}</p>
                                </div>
                                <button style={styles.manageBtn}>Manage</button>
                            </div>
                        ))}
                    </div>
                </div>

                <div style={styles.section}>
                    <h3>Today's Schedule</h3>
                    <div style={styles.taskList}>
                        {[
                            { time: '10:00', period: 'AM', event: 'Data Science 101', location: 'Room 203' },
                            { time: '2:00', period: 'PM', event: 'Office Hours', location: 'Building A • Room 415' }
                        ].map((schedule, idx) => (
                            <div key={idx} style={styles.taskItem}>
                                <div style={styles.taskDate}>
                                    <span style={styles.time}>{schedule.time}</span>
                                    <span style={styles.period}>{schedule.period}</span>
                                </div>
                                <div style={styles.taskInfo}>
                                    <h4>{schedule.event}</h4>
                                    <p>{schedule.location}</p>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </>
    );

    const renderAdminDashboard = () => (
        <>
            <div style={styles.statsGrid}>
                <div style={styles.statCard}>
                    <div style={{...styles.statIcon, backgroundColor: '#dc2626'}}>
                        <span className="material-icons">dashboard</span>
                    </div>
                    <div style={styles.statContent}>
                        <h3>Total Users</h3>
                        <p style={styles.statNumber}>1,234</p>
                    </div>
                </div>
                <div style={styles.statCard}>
                    <div style={{...styles.statIcon, backgroundColor: '#059669'}}>
                        <span className="material-icons">school</span>
                    </div>
                    <div style={styles.statContent}>
                        <h3>Active Courses</h3>
                        <p style={styles.statNumber}>42</p>
                    </div>
                </div>
                <div style={styles.statCard}>
                    <div style={{...styles.statIcon, backgroundColor: '#7c3aed'}}>
                        <span className="material-icons">person</span>
                    </div>
                    <div style={styles.statContent}>
                        <h3>Faculty Members</h3>
                        <p style={styles.statNumber}>68</p>
                    </div>
                </div>
                <div style={styles.statCard}>
                    <div style={{...styles.statIcon, backgroundColor: '#f59e0b'}}>
                        <span className="material-icons">trending_up</span>
                    </div>
                    <div style={styles.statContent}>
                        <h3>System Health</h3>
                        <p style={styles.statNumber}>98%</p>
                    </div>
                </div>
            </div>

            <div style={styles.dashboardContent}>
                <div style={styles.section}>
                    <h3>System Overview</h3>
                    <div style={styles.adminGrid}>
                        <div style={styles.adminCard}>
                            <span className="material-icons" style={styles.adminIcon}>people</span>
                            <h4>User Management</h4>
                            <p>Manage students, teachers, and administrators</p>
                            <button style={styles.adminBtn}>Manage Users</button>
                        </div>
                        <div style={styles.adminCard}>
                            <span className="material-icons" style={styles.adminIcon}>menu_book</span>
                            <h4>Course Management</h4>
                            <p>Create, edit, and manage all courses</p>
                            <button style={styles.adminBtn}>Manage Courses</button>
                        </div>
                        <div style={styles.adminCard}>
                            <span className="material-icons" style={styles.adminIcon}>analytics</span>
                            <h4>Reports & Analytics</h4>
                            <p>View system analytics and generate reports</p>
                            <button style={styles.adminBtn}>View Reports</button>
                        </div>
                        <div style={styles.adminCard}>
                            <span className="material-icons" style={styles.adminIcon}>settings</span>
                            <h4>System Settings</h4>
                            <p>Configure system-wide settings</p>
                            <button style={styles.adminBtn}>Settings</button>
                        </div>
                    </div>
                </div>

                <div style={styles.section}>
                    <h3>Recent Activities</h3>
                    <div style={styles.activityList}>
                        {[
                            { icon: 'person_add', action: 'New user registered', user: 'John Doe', time: '5 minutes ago' },
                            { icon: 'book', action: 'Course created', user: 'Dr. Smith', time: '1 hour ago' },
                            { icon: 'assignment_turned_in', action: 'Assignment graded', user: 'Prof. Johnson', time: '2 hours ago' },
                            { icon: 'security', action: 'Security update applied', user: 'System', time: '3 hours ago' }
                        ].map((activity, idx) => (
                            <div key={idx} style={styles.activityItem}>
                                <span className="material-icons" style={styles.activityIcon}>{activity.icon}</span>
                                <div style={styles.activityInfo}>
                                    <p><strong>{activity.action}</strong></p>
                                    <p style={styles.activityMeta}>{activity.user} • {activity.time}</p>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </>
    );

    const renderDashboardContent = () => {
        switch(user?.role) {
            case 'student':
                return renderStudentDashboard();
            case 'teacher':
                return renderTeacherDashboard();
            case 'admin':
                return renderAdminDashboard();
            default:
                return renderStudentDashboard();
        }
    };

    const getRoleDisplay = () => {
        switch(user?.role) {
            case 'student':
                return 'Student Portal';
            case 'teacher':
                return 'Teacher Portal';
            case 'admin':
                return 'Admin Portal';
            default:
                return 'Dashboard';
        }
    };

    const getRoleColor = () => {
        switch(user?.role) {
            case 'student':
                return '#3b82f6';
            case 'teacher':
                return '#10b981';
            case 'admin':
                return '#8b5cf6';
            default:
                return '#3b82f6';
        }
    };

    return (
        <div style={styles.dashboardContainer}>
            <div style={styles.sidebar}>
                <div style={styles.sidebarHeader}>
                    <h2 style={styles.logo}>EduPortal</h2>
                    <p style={{...styles.userType, color: getRoleColor()}}>{getRoleDisplay()}</p>
                </div>
                
                <nav style={styles.sidebarNav}>
                    {[
                        { id: 'overview', icon: 'dashboard', label: 'Overview' },
                        { id: 'courses', icon: 'school', label: user?.role === 'admin' ? 'All Courses' : 'My Courses' },
                        { id: 'calendar', icon: 'event', label: 'Calendar' },
                        { id: 'messages', icon: 'message', label: 'Messages' },
                        user?.role === 'admin' && { id: 'users', icon: 'people', label: 'Users' },
                        user?.role === 'teacher' && { id: 'grades', icon: 'grading', label: 'Grades' },
                        { id: 'settings', icon: 'settings', label: 'Settings' }
                    ].filter(Boolean).map(item => (
                        <button 
                            key={item.id}
                            style={{
                                ...styles.navItem,
                                ...(activeTab === item.id ? styles.navItemActive : {})
                            }}
                            onClick={() => setActiveTab(item.id)}
                        >
                            <span className="material-icons">{item.icon}</span>
                            {item.label}
                        </button>
                    ))}
                </nav>

                <div style={styles.sidebarFooter}>
                    <div style={styles.userInfo}>
                        <div style={{...styles.userAvatar, backgroundColor: getRoleColor()}}>
                            {user?.name?.charAt(0).toUpperCase()}
                        </div>
                        <div style={styles.userDetails}>
                            <p style={styles.userName}>{user?.name}</p>
                            <p style={styles.userEmail}>{user?.email}</p>
                        </div>
                    </div>
                    <button style={styles.logoutBtn} onClick={handleLogout}>
                        <span className="material-icons">logout</span>
                        Logout
                    </button>
                </div>
            </div>

            <div style={styles.mainContent}>
                <div style={styles.header}>
                    <h1>Welcome back, {user?.name}!</h1>
                    <p>Here's what's happening with your account today.</p>
                </div>

                {renderDashboardContent()}
            </div>
        </div>
    );
};

